// n8n 2.x: body fields are promoted to top-level json keys by the Webhook node.
// Fallback chain covers edge cases (nested body, raw string body).
const item = $input.first().json;

const raw =
  item.pdf_url ||
  item.body?.pdf_url ||
  (typeof item.body === 'string' ? JSON.parse(item.body).pdf_url : undefined);

if (!raw) {
  throw new Error('Missing pdf_url. Send: {"pdf_url": "https://..."}');
}

// Sanitize: strip whitespace, newlines, zero-width chars
const pdfUrl = String(raw).replace(/[\s\u200B-\u200D\uFEFF]/g, '');

// Validate URL using regex (avoids n8n VM URL constructor issues)
const urlPattern = /^https?:\/\/.+/i;
if (!urlPattern.test(pdfUrl)) {
  throw new Error('pdf_url must start with http:// or https://. Got: ' + pdfUrl.substring(0, 100));
}

return [{ json: { pdf_url: pdfUrl } }];

const response = $input.first().json;

// Extract text from Gemini response
let rawText = '';
try {
  rawText = response.candidates[0].content.parts[0].text.trim();
} catch (e) {
  throw new Error('Gemini returned an unexpected response structure: ' + JSON.stringify(response));
}

// Check for the "no pnl found" sentinel
if (rawText.toLowerCase() === 'no pnl found') {
  return [{ json: { success: false, error: 'no pnl found' } }];
}

// Strip markdown code fences if present (e.g. ```json ... ```)
let cleaned = rawText
  .replace(/^```json\s*\n?/i, '')
  .replace(/^```\s*\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Gemini returned invalid JSON. Raw text: ' + rawText.substring(0, 500));
}

// Basic sanity check: must have at least row1
if (!parsed.row1 || !Array.isArray(parsed.row1)) {
  throw new Error('Parsed JSON is missing row1 (header row). Output: ' + JSON.stringify(parsed).substring(0, 500));
}

return [{ json: { success: true, result: parsed } }];

// Prepare the metadata required by Google Files API upload.
const binaryData = $input.first().binary;
if (!binaryData) {
  throw new Error('PDF download returned no binary data. Check the URL.');
}

const binaryKey = Object.keys(binaryData)[0];
const fileData = binaryData[binaryKey];

return [{
  json: {
    fileSize: fileData.bytes,
    mimeType: fileData.mimeType || 'application/pdf',
    binaryKey: binaryKey
  },
  binary: binaryData
}];

// Handle PDF download errors (404, 403, timeouts, etc.)
const item = $input.first().json;

let userMessage = 'Failed to download the PDF.';
const httpCode = item?.errorDetails?.httpCode || item?.code;

if (String(httpCode) === '404') {
  userMessage = 'The PDF link could not be found (404). The file may have been moved or removed from BSE. Please verify the URL.';
} else if (String(httpCode) === '403') {
  userMessage = 'Access to this PDF is forbidden (403). BSE may be blocking automated downloads.';
} else if (String(httpCode) === '500') {
  userMessage = 'BSE server error (500). Please try again later.';
} else {
  userMessage = 'Failed to download the PDF: ' + (item?.message || item?.errorMessage || 'Unknown error');
}

return [{ json: { success: false, error: userMessage, errorCode: 'PDF_DOWNLOAD_FAILED' } }];
